import numpy as np

def sleep_policy(traffic_loads: np.ndarray,
                 neighbor_matrix: np.ndarray,
                 prev_active: np.ndarray) -> np.ndarray:
    """Decide which cells sleep and which stay active."""
    N = len(traffic_loads)
    OFFLOAD_OVERHEAD = 2.0
    HARD_LIMIT = 0.80
    SOFT_LIMIT = 0.74
    UPGRADE_THRESHOLD = 0.76
    WAKE_PATIENCE = 4
    STABILITY_REQUIRED = 5

    # Initialize persistent state if not present
    if not hasattr(sleep_policy, "configs"):
        # Configs ordered from LEAST aggressive (all active) to MOST aggressive (most sleep)
        configs = []
        configs.append(np.ones(N, dtype=np.int32))

        # Config 1: Center sleeps
        c1 = np.ones(N, dtype=np.int32); c1[0] = 0
        configs.append(c1)

        # Configs 2-6: Center + i ring cells sleep
        for i in range(1, 6):
            ci = np.ones(N, dtype=np.int32)
            ci[0] = 0
            for j in range(1, i + 1):
                ci[j] = 0
            configs.append(ci)

        sleep_policy.configs = configs
        sleep_policy.current_config_idx = 0
        sleep_policy.infeasible_streak = 0
        sleep_policy.stable_streak = 0

    # Sync current_config_idx with prev_active
    found_prev = False
    for idx, cfg in enumerate(sleep_policy.configs):
        if np.array_equal(cfg, prev_active):
            sleep_policy.current_config_idx = idx
            found_prev = True
            break
    if not found_prev:
        sleep_policy.current_config_idx = 0

    # 1. Recover base loads
    base_loads = np.zeros(N)
    for i in range(N):
        if prev_active[i] == 0:
            base_loads[i] = traffic_loads[i]
        else:
            base_loads[i] = traffic_loads[i]
            for j in range(N):
                if neighbor_matrix[i, j] == 1 and prev_active[j] == 0:
                    active_nbrs_j = int(np.sum(neighbor_matrix[j] * prev_active))
                    if active_nbrs_j > 0:
                        base_loads[i] -= (traffic_loads[j] * OFFLOAD_OVERHEAD / active_nbrs_j)

    def calculate_candidate_load(candidate_config, base_loads, neighbor_matrix):
        cand_load = base_loads.copy()
        for i in range(N):
            if candidate_config[i] == 1:
                for j in range(N):
                    if neighbor_matrix[i, j] == 1 and candidate_config[j] == 0:
                        active_nbrs_j = int(np.sum(neighbor_matrix[j] * candidate_config))
                        if active_nbrs_j > 0:
                            cand_load[i] += (base_loads[j] * OFFLOAD_OVERHEAD / active_nbrs_j)
        return cand_load

    # 2. Evaluate current configuration's load
    current_max_load = 0
    for i in range(N):
        if prev_active[i] == 1:
            current_max_load = max(current_max_load, traffic_loads[i])

    # 3. Hysteresis Logic
    if current_max_load > HARD_LIMIT:
        sleep_policy.current_config_idx = 0
        sleep_policy.infeasible_streak = 0
        sleep_policy.stable_streak = 0
    elif current_max_load > SOFT_LIMIT:
        sleep_policy.infeasible_streak += 1
        if sleep_policy.infeasible_streak >= WAKE_PATIENCE:
            sleep_policy.current_config_idx = max(0, sleep_policy.current_config_idx - 1)
            sleep_policy.infeasible_streak = 0
            sleep_policy.stable_streak = 0
    else:
        sleep_policy.infeasible_streak = 0
        can_upgrade = False
        next_idx = sleep_policy.current_config_idx + 1
        if next_idx < len(sleep_policy.configs):
            candidate_cfg = sleep_policy.configs[next_idx]
            coverage_ok = True
            for i in range(N):
                if candidate_cfg[i] == 0:
                    if np.sum(neighbor_matrix[i] * candidate_cfg) == 0:
                        coverage_ok = False
                        break
            if coverage_ok:
                cand_load = calculate_candidate_load(candidate_cfg, base_loads, neighbor_matrix)
                active_cells = cand_load[candidate_cfg == 1]
                if len(active_cells) > 0 and np.max(active_cells) <= UPGRADE_THRESHOLD:
                    can_upgrade = True
                elif len(active_cells) == 0:
                    can_upgrade = True

        if can_upgrade:
            sleep_policy.stable_streak += 1
            if sleep_policy.stable_streak >= STABILITY_REQUIRED:
                sleep_policy.current_config_idx = next_idx
                sleep_policy.stable_streak = 0
                sleep_policy.infeasible_streak = 0
        else:
            sleep_policy.stable_streak = 0

    return sleep_policy.configs[sleep_policy.current_config_idx].copy()

import numpy as np

# Constants
OFFLOAD_OVERHEAD = 2.0
SOFT_LIMIT = 0.74
HARD_LIMIT = 0.80
UPGRADE_LIMIT = 0.76
WAKE_PATIENCE = 4
UPGRADE_STABILITY = 5

def sleep_policy(traffic_loads: np.ndarray,
                 neighbor_matrix: np.ndarray,
                 prev_active: np.ndarray) -> np.ndarray:
    """Decide which cells sleep and which stay active."""

    N = len(traffic_loads)

    # Initialize state on the function object if not present
    if not hasattr(sleep_policy, "config_idx"):
        sleep_policy.config_idx = 0 # Start with all-active
        sleep_policy.infeasible_streak = 0
        sleep_policy.stable_streak = 0

    # Define configurations
    # We need to be VERY careful. The error says cell 6 was overloaded.
    # Cell 6 is a ring cell. If cell 0 (center) and cell 1 (ring) sleep, 
    # cell 6's load might increase significantly.
    # Let's use a very safe set of configurations.
    configs = [
        np.ones(N, dtype=np.int32), # 0: All active
        np.array([0, 1, 1, 1, 1, 1, 1], dtype=np.int32), # 1: Center sleeps
        np.array([1, 1, 1, 1, 1, 1, 0], dtype=np.int32), # 2: One ring sleeps (cell 6)
        np.array([1, 0, 1, 1, 1, 1, 1], dtype=np.int32), # 3: One ring sleeps (cell 1)
        np.array([1, 1, 1, 1, 1, 0, 1], dtype=np.int32), # 4: One ring sleeps (cell 5)
    ]

    def is_feasible(config, loads, neighbors, limit, prev_active_val):
        N_local = len(loads)
        own_loads = np.zeros(N_local)
        for i in range(N_local):
            if prev_active_val[i] == 0:
                own_loads[i] = loads[i]
            else:
                own_loads[i] = loads[i]
                for j in range(N_local):
                    if neighbors[i, j] == 1 and prev_active_val[j] == 0:
                        active_nbrs_j = int(np.sum(neighbors[j] * prev_active_val))
                        if active_nbrs_j > 0:
                            own_loads[i] -= loads[j] * OFFLOAD_OVERHEAD / active_nbrs_j

        new_eff_loads = np.zeros(N_local)
        for i in range(N_local):
            if config[i] == 1:
                new_eff_loads[i] = own_loads[i]
                for j in range(N_local):
                    if neighbors[i, j] == 1 and config[j] == 0:
                        active_nbrs_j_in_new = int(np.sum(neighbors[j] * config))
                        if active_nbrs_j_in_new > 0:
                            new_eff_loads[i] += own_loads[j] * OFFLOAD_OVERHEAD / active_nbrs_j_in_new
            else:
                new_eff_loads[i] = 0.0

        for i in range(N_local):
            if config[i] == 0:
                if np.sum(neighbors[i] * config) == 0:
                    return False, 0.0

        max_l = 0.0
        for i in range(N_local):
            if config[i] == 1:
                if new_eff_loads[i] > limit:
                    return False, np.max(new_eff_loads)
                if new_eff_loads[i] > max_l:
                    max_l = new_eff_loads[i]
        return True, max_l

    current_max_load = 0.0
    for i in range(N):
        if prev_active[i] == 1:
            if traffic_loads[i] > current_max_load:
                current_max_load = traffic_loads[i]

    if current_max_load > HARD_LIMIT:
        sleep_policy.config_idx = max(0, sleep_policy.config_idx - 1)
        sleep_policy.infeasible_streak = 0
        sleep_policy.stable_streak = 0
    elif current_max_load > SOFT_LIMIT:
        sleep_policy.infeasible_streak += 1
        if sleep_policy.infeasible_streak >= WAKE_PATIENCE:
            sleep_policy.config_idx = max(0, sleep_policy.config_idx - 1)
            sleep_policy.infeasible_streak = 0
            sleep_policy.stable_streak = 0
    else:
        sleep_policy.infeasible_streak = 0
        sleep_policy.stable_streak += 1
        if sleep_policy.stable_streak >= UPGRADE_STABILITY:
            next_idx = sleep_policy.config_idx + 1
            if next_idx < len(configs):
                feasible, _ = is_feasible(configs[next_idx], traffic_loads, neighbor_matrix, UPGRADE_LIMIT, prev_active)
                if feasible:
                    sleep_policy.config_idx = next_idx
                    sleep_policy.stable_streak = 0

    return configs[sleep_policy.config_idx]
